    CapFrameX,
}

impl ToolActionId {
    /// Returns the stable string id used by UI callbacks and later tracing.
    pub const fn as_str(self) -> &'static str {
        match self {
            Self::DowngradeManager => "tools.downgrade_manager",
            Self::ArchivePatcher => "tools.archive_patcher",
